# [doc = " The canonical, deterministic identity encoding (ADR-003) — **the single source of truth for spore"] # [doc = " identity**. Metadata (`name`/`version`/`authors`/…) is **excluded** — only the code-by-hash DAG, the"] # [doc = " dependency hash edges, the germination surface, and the project kind bear identity. Two builds of the"] # [doc = " same code+deps yield the same spore hash. **Downstream verifiers (e.g. `mycelium-std-spore::verify`)"] # [doc = " MUST call this function — never re-implement the encoding:** a parallel copy is exactly how the"] # [doc = " `v0`/`v1` split arose (DRY; the verify path stamped a stale `v0` while `build_spore` stamped `v1`)."] pub fn content_address (kind : ProjectKind , surface : & [String] , sources : & [SourceFile] , deps : & [ResolvedDep] ,) -> ContentHash { let mut s = String :: from ("mycelium-spore-v1
") ; s . push_str (& format ! ("kind:{}
" , kind_str (kind))) ; s . push_str (& format ! ("surface:{}
" , surface . len ())) ; for name in surface { push_field (& mut s , name) ; } s . push_str (& format ! ("code:{}
" , sources . len ())) ; for f in sources { push_field (& mut s , & f . path) ; push_field (& mut s , f . hash . as_str ()) ; } s . push_str (& format ! ("deps:{}
" , deps . len ())) ; for d in deps { push_field (& mut s , & d . name) ; push_field (& mut s , & d . phylum) ; push_field (& mut s , & d . hash) ; } let hex = blake3 :: hash (s . as_bytes ()) . to_hex () ; ContentHash :: from_parts ("blake3" , hex . as_str ()) . expect ("blake3 hex is a valid digest") }

fn walk (root : & Path , dir : & Path , depth : usize , out : & mut Vec < SourceFile > ,) -> Result < () , SporeError > { if depth > MAX_WALK_DEPTH { return Err (SporeError :: Publish (format ! ("source tree under {} nests deeper than {MAX_WALK_DEPTH} directories at {} — refusing \
             to recurse further (a tree this deep is not a valid layout; likely a symlink cycle or \
             an adversarial input). Flatten the tree or remove the offending link (DN-40/G2)" , root . display () , dir . display () ,))) ; } let entries = std :: fs :: read_dir (dir) . map_err (| e | SporeError :: Io (format ! ("{}: {e}" , dir . display ()))) ? ; let mut paths : Vec < PathBuf > = entries . filter_map (| e | e . ok () . map (| e | e . path ())) . collect () ; paths . sort () ; for path in paths { let name = path . file_name () . and_then (| s | s . to_str ()) . unwrap_or_default () ; if name . starts_with ('.') || name == "target" { continue ; } let meta = std :: fs :: symlink_metadata (& path) . map_err (| e | SporeError :: Io (format ! ("{}: {e}" , path . display ()))) ? ; if meta . file_type () . is_symlink () { continue ; } if meta . is_dir () { walk (root , & path , depth + 1 , out) ? ; } else if meta . is_file () && path . extension () . is_some_and (| x | x == "myc") { let bytes = std :: fs :: read (& path) . map_err (| e | SporeError :: Io (format ! ("{}: {e}" , path . display ()))) ? ; let hex = blake3 :: hash (& bytes) . to_hex () ; let hash = ContentHash :: from_parts ("blake3" , hex . as_str ()) . expect ("blake3 hex is a valid digest") ; let rel = path . strip_prefix (root) . unwrap_or (& path) . to_string_lossy () . replace ('\\' , "/") ; out . push (SourceFile { path : rel , hash }) ; } } Ok (()) }

# [doc = " The `EXPLAIN` of a built spore (no black box): the identity receipt, the surface, the code by hash, the"] # [doc = " dependency edges, and the metadata — the metadata explicitly marked *not* identity (ADR-003)."] # [must_use] pub fn explain (spore : & Spore) -> String { let mut out = format ! ("spore: {}  →  {}
" , spore . name , spore . id . as_str ()) ; out . push_str (& format ! ("  kind:    {}
" , kind_str (spore . kind))) ; out . push_str (& format ! ("  surface: {}
" , spore . surface . join (", "))) ; out . push_str (& format ! ("  code:    {} source file(s)
" , spore . sources . len ())) ; for f in & spore . sources { out . push_str (& format ! ("    {} {}
" , f . path , f . hash . as_str ())) ; } out . push_str (& format ! ("  deps:    {}
" , spore . deps . len ())) ; for d in & spore . deps { let v = d . version . as_deref () . unwrap_or ("*") ; out . push_str (& format ! ("    {} → {} {} (version {v})
" , d . name , d . phylum , d . hash)) ; } let ver = spore . version . as_deref () . unwrap_or ("—") ; out . push_str (& format ! ("  metadata: name={}, version={ver}  [not identity — ADR-003]
" , spore . name)) ; out }
